#include <iostream>
#include <source_location>
#include <string>

void log_error(const std::string& msg,
               const std::source_location& loc = std::source_location::current()) {
    std::cerr << "[خطأ] " << loc.file_name() << ':'
              << loc.line() << " في "
              << loc.function_name() << ": "
              << msg << '\n';
}

int main() {
    int x = -1;
    if (x < 0) {
        log_error("القيمة سالبة");
        // [خطأ] main.cpp:16 في main: القيمة سالبة
    }
}

#include <iostream>
#include <source_location>

// الطريقة القديمة بالماكروات — غير أنيقة
#define OLD_LOG(msg) std::cerr << __FILE__ << ":" << __LINE__ << ": " << msg << '\n'

// الطريقة الحديثة — آمنة ونظيفة
void modern_log(const std::string& msg,
                const std::source_location& loc = std::source_location::current()) {
    std::cerr << loc.file_name() << ":" << loc.line() << ": " << msg << '\n';
}

int main() {
    OLD_LOG("قديم");       // يعمل لكنه ماكرو — مشاكل محتملة
    modern_log("حديث");     // دالة عادية — آمنة ونظيفة
}

#include <iostream>
#include <source_location>
#include <string>

class Tracer {
    int indent = 0;
public:
    void enter(const std::string& name,
               const std::source_location& loc = std::source_location::current()) {
        std::cout << std::string(indent, ' ') << "→ " << name
                  << " (" << loc.file_name() << ":" << loc.line() << ")" << '\n';
        indent += 2;
    }

    void exit(const std::string& name) {
        indent -= 2;
        std::cout << std::string(indent, ' ') << "← " << name << '\n';
    }
};

static Tracer tracer;

void process_data() {
    tracer.enter(__func__);
    // معالجة البيانات هنا
    tracer.exit(__func__);
}

int main() {
    tracer.enter(__func__);
    process_data();
    tracer.exit(__func__);
    // → main (main.cpp:29)
    //   → process_data (main.cpp:20)
    //   ← process_data
    // ← main
}
